INSERT INTO news VALUES(78,'http://bair.berkeley.edu/blog/2025/11/01/rl-without-td-learning/','RL without TD learning',replace('\n\n\n\n\n\n\n\n\n\n\n\n\nIn this post, I’ll introduce a reinforcement learning (RL) algorithm based on an “alternative” paradigm: divide and conquer. Unlike traditional methods, this algorithm is not based on temporal difference (TD) learning (which has scalabil','\n',char(10)),'https://bair.berkeley.edu/static/blog/rl-without-td-learning/teaser_short.png','2025-11-01T09:00:00','Berkeley AI Research','AI');
INSERT INTO news VALUES(79,'http://bair.berkeley.edu/blog/2025/09/01/qwem-word2vec-theory/','What exactly does word2vec learn?',replace('\n\n\n\n\n\n\n\n\n\n\n\n\nWhat exactly does word2vec learn, and how? Answering this question amounts to understanding representation learning in a minimal yet interesting language modeling task. Despite the fact that word2vec is a well-known precursor to modern l','\n',char(10)),'https://bair.berkeley.edu/static/blog/qwem-word2vec-theory/fig1.c8u1a3E7_Z23iPso.webp','2025-09-01T09:00:00','Berkeley AI Research','AI');
