INSERT INTO news VALUES(206,'https://aws.amazon.com/blogs/aws/20-years-in-the-aws-cloud-how-time-flies/','20 years in the AWS Cloud – how time flies!','Celebrating twenty years of innovation in ML and AI technology at AWS. Countless developers—myself included—have embraced cloud computing and actively used its capabilities to accomplish what was previously impossible.','https://d2908q01vomqb2.cloudfront.net/da4b9237bacccdf19c0760cab7aec4a8359010b0/2026/03/16/2026-aws-20th-200x200-1.jpg','2026-03-19T13:35:54','AWS News','Cloud');
