INSERT INTO news VALUES(209,'https://aws.amazon.com/blogs/aws/twenty-years-of-amazon-s3-and-building-whats-next/','Twenty years of Amazon S3 and building what’s next','Some reflections on 20 years of innovations in Amazon S3 including S3 Tables, S3 Vectors and S3 Metadata.','https://d2908q01vomqb2.cloudfront.net/da4b9237bacccdf19c0760cab7aec4a8359010b0/2026/03/10/s3-illustration-2-1024x538.png','2026-03-13T12:58:39','AWS News','Cloud');
INSERT INTO news VALUES(210,'https://aws.amazon.com/blogs/aws/introducing-account-regional-namespaces-for-amazon-s3-general-purpose-buckets/','Introducing account regional namespaces for Amazon S3 general purpose buckets','AWS launches a new feature of Amazon S3 that lets you create general purpose buckets in your own account regional namespace simplifying bucket creation and management as your data storage needs grow in size and scope.','https://d2908q01vomqb2.cloudfront.net/da4b9237bacccdf19c0760cab7aec4a8359010b0/2026/02/12/2026-s3-bucket-account-regional-namespace.png','2026-03-12T21:18:55','AWS News','Cloud');
INSERT INTO news VALUES(211,'https://aws.amazon.com/blogs/aws/aws-weekly-roundup-amazon-connect-health-bedrock-agentcore-policy-gameday-europe-and-more-march-9-2026/','AWS Weekly Roundup: Amazon Connect Health, Bedrock AgentCore Policy, GameDay Europe, and more (March 9, 2026)','Fiti AWS Student Community Kenya! Last week was an incredible whirlwind: a round of meetups, hands-on workshops, and career discussions across Kenya that culminated with the AWS Student Community Day at Meru University of Science and Technology, with','https://d2908q01vomqb2.cloudfront.net/da4b9237bacccdf19c0760cab7aec4a8359010b0/2026/03/09/1772482486843-1-1024x500.jpg','2026-03-09T16:15:35','AWS News','Cloud');
INSERT INTO news VALUES(212,'https://aws.amazon.com/blogs/aws/introducing-openclaw-on-amazon-lightsail-to-run-your-autonomous-private-ai-agents/','Introducing OpenClaw on Amazon Lightsail to run your autonomous private AI agents','AWS launches OpenClaw on Amazon Lightsail to run OpenClaw instance, pairing your browser, enabling AI capabilities, and optionally connecting messaging channels. Your Lightsail OpenClaw instance is pre-configured with Amazon Bedrock for starting with','https://d2908q01vomqb2.cloudfront.net/da4b9237bacccdf19c0760cab7aec4a8359010b0/2026/03/04/2026-openclaw-lightsail-1.png','2026-03-04T20:04:16','AWS News','Cloud');
INSERT INTO news VALUES(213,'https://www.prisma.io/blog/mongodb-without-compromise','MongoDB Without Compromise','Prisma Next brings a MongoDB-native experience to TypeScript with type-safe queries, real migrations, polymorphic models, embedded collections, and typed aggregation pipelines.','https://via.placeholder.com/400x250?text=Tech+News','2026-04-13T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(214,'https://www.prisma.io/blog/announcing-query-insights-for-prisma-postgres','Announcing Query Insights For Prisma Postgres','Query Insights gives you built-in visibility into how your database queries behave in production. It is included in Prisma Postgres and works out of the box without any setup.','https://via.placeholder.com/400x250?text=Tech+News','2026-04-09T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(215,'https://www.prisma.io/blog/how-prisma-build-with-agentic-ai','Agentic Engineering: How Prisma Builds with AI','In three months, Prisma fundamentally changed how it builds software by rethinking the relationship between engineers and AI agents. Here''s what we learned building Prisma Next with agentic engineering.','https://via.placeholder.com/400x250?text=Tech+News','2026-03-30T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(216,'https://www.prisma.io/blog/rethinking-database-migrations','Rethinking Database Migrations','Database migrations are brittle and they break when you''re most vulnerable; when you''re deploying to production. Prisma Next migrations make them explicit, verifiable and safe to retry.','https://via.placeholder.com/400x250?text=Tech+News','2026-03-27T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(217,'https://www.prisma.io/blog/sunsetting-prisma-optimize','Sunsetting Prisma Optimize','Prisma Optimize is being sunset as we move query observability directly into Prisma Postgres through Query Insights.','https://via.placeholder.com/400x250?text=Tech+News','2026-03-23T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(218,'https://www.prisma.io/blog/prisma-next-roadmap','Prisma Next Roadmap','Have you been wondering when you can start using Prisma Next in your app? Take a look at our roadmap to find out.','https://via.placeholder.com/400x250?text=Tech+News','2026-03-20T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(219,'https://www.prisma.io/blog/rebuilding-the-prisma-docs','Rebuilding the Prisma Docs: A New Framework, Design, and Structure','Learn how the Prisma team rebuilt their docs from scratch using Fumadocs, improved search with Mixedbread, and launched without disrupting day-to-day work.','https://via.placeholder.com/400x250?text=Tech+News','2026-03-09T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(220,'https://www.prisma.io/blog/the-next-evolution-of-prisma-orm','The Next Evolution of Prisma ORM','A look at Prisma Next, a ground-up rethink of Prisma that improves queries, extensibility, migrations, and AI-friendly workflows while keeping Prisma’s schema-first approach.','https://via.placeholder.com/400x250?text=Tech+News','2026-03-04T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(221,'https://www.prisma.io/blog/prisma-orm-v7-4-query-caching-partial-indexes-and-major-performance-improvements','Prisma ORM v7.4: Query Caching & Performance Boost','Prisma ORM v7.4 introduces query caching, partial indexes, and BigInt precision fixes—delivering significant performance improvements under load.','https://via.placeholder.com/400x250?text=Tech+News','2026-02-19T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(222,'https://www.prisma.io/blog/prisma-7-ama-clearing-up-the-why-behind-the-changes','Prisma 7 Explained: Performance, Architecture, and AMA Answers','Prisma 7 introduces major architectural changes. We answer community AMA questions on performance, database support, the new client generator, and what’s next.','https://via.placeholder.com/400x250?text=Tech+News','2026-02-13T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(223,'https://www.prisma.io/blog/prisma-orm-7-3-0','Prisma ORM 7.3.0: Faster Query Compilation, Safer BigInt JSON, Better Adapters','Prisma ORM 7.3.0 adds a new compilerBuild option (fast or small), speeds up raw queries by bypassing compilation, improves MSSQL and better-sqlite3 stability, reverts mapped enum behavior, and preserves BigInt precision in relationJoins JSON aggregat','https://via.placeholder.com/400x250?text=Tech+News','2026-01-21T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(224,'https://www.prisma.io/blog/announcing-prisma-orm-7-2-0','Prisma ORM 7.2.0 Released: CLI Improvements, Bug Fixes & Better Configs','Prisma ORM 7.2.0 is out with key improvements: the return of the --url flag, smarter prisma init configs for Node and Bun, better CLI errors, and fixes for @db.Money. Upgrade today.','https://via.placeholder.com/400x250?text=Tech+News','2025-12-17T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(225,'https://www.prisma.io/blog/prisma-7-performance-benchmarks','Understanding Prisma 7 Performance Benchmarks','We reviewed community benchmarks comparing Prisma 6 and Prisma 7. Here’s what they measure, where regressions exist, and how we’re fixing them.','https://via.placeholder.com/400x250?text=Tech+News','2025-12-16T00:00:00','Prisma Blog','Backend');
