INSERT INTO news VALUES(228,'https://www.prisma.io/blog/how-deno-and-prisma-partnered-to-power-per-branch-databases','How Deno and Prisma Partnered to Power Per-Branch Databases','Deno Deploy integrates Prisma Postgres for instant per-branch databases, enabling seamless full-stack deployment and modern developer workflows.','https://via.placeholder.com/400x250?text=Tech+News','2025-10-29T00:00:00','Prisma Blog','Backend');
