INSERT INTO news VALUES(231,'https://www.prisma.io/blog/orm-v6-17-0-new-usage-metrics-and-direct-connections-in-ga-for-prisma-postgres','ORM v6.17.0, New Usage Metrics & Direct Connections in GA for Prisma Postgres','Prisma ORM v6.17.0 is out with fixes and improvements. Connecting to Prisma Postgres via your favorite ORM/DB tool is now GA. Read the full update.','https://via.placeholder.com/400x250?text=Tech+News','2025-10-08T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(232,'https://www.prisma.io/blog/introducing-instant-app-deployments-in-partnership-with-vercel','Introducing Instant App Deployments in Partnership with Vercel','Instant App Deployment with Prisma Postgres and Vercel makes going from generated code to production effortless. Provision a Postgres database, deploy globally, and let users claim full ownership with a single API call. Perfect for AI coding platform','https://via.placeholder.com/400x250?text=Tech+News','2025-09-23T00:00:00','Prisma Blog','Backend');
INSERT INTO news VALUES(233,'https://kubernetes.io/blog/2026/04/24/kubernetes-v1-36-fine-grained-kubelet-authorization-ga/','Kubernetes v1.36: Fine-Grained Kubelet API Authorization Graduates to GA',replace('On behalf of Kubernetes SIG Auth and SIG Node, we are pleased to announce the\ngraduation of fine-grained kubelet API authorization to General Availability\n(GA) in Kubernetes v1.36!\nThe KubeletFineGrainedAuthz feature gate was introduced as an opt-in ','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-24T18:35:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(234,'https://kubernetes.io/blog/2026/04/23/kubernetes-v1-36-userns-ga/','Kubernetes v1.36: User Namespaces in Kubernetes are finally GA',replace('After several years of development, User Namespaces support in\nKubernetes reached General Availability (GA) with the v1.36 release.\nThis is a Linux-only feature.\nFor those of us working on low level container runtimes and rootless\ntechnologies, this ','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-23T18:35:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(235,'https://kubernetes.io/blog/2026/04/22/breaking-changes-in-selinux-volume-labeling/','SELinux Volume Label Changes goes GA (and likely implications in v1.37)',replace('If you run Kubernetes on Linux with SELinux in enforcing mode, plan ahead: a future release (anticipated to be v1.37) is\nexpected to turn the SELinuxMount feature gate on by default. This makes volume setup faster\nfor most workloads, but it can break','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-22T18:35:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(236,'https://kubernetes.io/blog/2026/04/22/kubernetes-v1-36-release/','Kubernetes v1.36: ハル (Haru)',replace('Editors: Chad M. Crowell, Kirti Goyal, Sophia Ugochukwu, Swathi Rao, Utkarsh Umre\nSimilar to previous releases, the release of Kubernetes v1.36 introduces new stable, beta, and alpha features. The consistent delivery of high-quality releases undersco','\n',char(10)),'https://kubernetes.io/blog/2026/04/22/kubernetes-v1-36-release/k8s-v1.36.svg','2026-04-22T00:00:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(237,'https://kubernetes.io/blog/2026/04/21/gateway-api-v1-5/','Gateway API v1.5: Moving features to Stable',replace('\nThe Kubernetes SIG Network community presents the release of Gateway API (v1.5)!\nReleased on February 27, 2026, version 1.5 is our biggest release yet, and concentrates on moving existing Experimental features to Standard (Stable).\nThe Gateway API v','\n',char(10)),'https://kubernetes.io/blog/2026/04/21/gateway-api-v1-5/gateway-api-logo.svg','2026-04-21T16:30:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(238,'https://kubernetes.io/blog/2026/03/30/kubernetes-v1-36-sneak-peek/','Kubernetes v1.36 Sneak Peek',replace('Kubernetes v1.36 is coming at the end of April 2026. This release will include removals and deprecations, and it is packed with an impressive number of\nenhancements. Here are some of the features we are most excited about in this cycle!\nPlease note t','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-03-30T00:00:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(239,'https://kubernetes.io/blog/2026/03/20/ingress2gateway-1-0-release/','Announcing Ingress2Gateway 1.0: Your Path to Gateway API',replace('With the Ingress-NGINX retirement scheduled for March 2026, the Kubernetes networking landscape is at a turning point.\nFor most organizations, the question isn''t whether to migrate to Gateway API, but how to do so safely.\nMigrating from Ingress to Ga','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-03-20T19:00:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(240,'https://kubernetes.io/blog/2026/03/20/running-agents-on-kubernetes-with-agent-sandbox/','Running Agents on Kubernetes with Agent Sandbox','The landscape of artificial intelligence is undergoing a massive architectural shift. In the early days of generative AI, interacting with a model was often treated as a transient, stateless function call: a request that spun up, executed for perhaps','https://via.placeholder.com/400x250?text=Tech+News','2026-03-20T18:00:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(241,'https://kubernetes.io/blog/2026/03/18/securing-production-debugging-in-kubernetes/','Securing Production Debugging in Kubernetes','During production debugging, the fastest route is often broad access such as cluster-admin (a ClusterRole that grants administrator-level access), shared bastions/jump boxes, or long-lived SSH keys. It works in the moment, but it comes with two commo','https://via.placeholder.com/400x250?text=Tech+News','2026-03-18T18:00:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(242,'https://kubernetes.io/blog/2026/03/17/image-promoter-rewrite/','The Invisible Rewrite: Modernizing the Kubernetes Image Promoter',replace('Every container image you pull from registry.k8s.io got there through\nkpromo, the Kubernetes image\npromoter. It copies images from staging registries to\nproduction, signs them with cosign, replicates\nsignatures across more than 20 regional mirrors, a','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-03-17T00:00:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(243,'https://kubernetes.io/blog/2026/03/09/announcing-ai-gateway-wg/','Announcing the AI Gateway Working Group','The community around Kubernetes includes a number of Special Interest Groups (SIGs) and Working Groups (WGs) facilitating discussions on important topics between interested contributors. Today, we''re excited to announce the formation of the AI Gatewa','https://via.placeholder.com/400x250?text=Tech+News','2026-03-09T18:00:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(244,'https://kubernetes.io/blog/2026/02/27/ingress-nginx-before-you-migrate/','Before You Migrate: Five Surprising Ingress-NGINX Behaviors You Need to Know',replace('As announced November 2025, Kubernetes will retire Ingress-NGINX in March 2026.\nDespite its widespread usage, Ingress-NGINX is full of surprising defaults and side effects that are probably present in your cluster today.\nThis blog highlights these be','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-02-27T15:30:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(245,'https://kubernetes.io/blog/2026/02/26/ccm-new-metric-route-sync-total/','Kubernetes v1.36: New Metric for Route Sync in the Cloud Controller Manager',replace('Kubernetes v1.36 introduces a new alpha counter metric route_controller_route_sync_total\nto the Cloud Controller Manager (CCM) route controller implementation at\nk8s.io/cloud-provider. This metric\nincrements each time routes are synced with the cloud','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-02-26T00:00:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(246,'https://kubernetes.io/blog/2026/02/12/sig-architecture-api-spotlight/','Spotlight on SIG Architecture: API Governance',replace('This is the fifth interview of a SIG Architecture Spotlight series that covers the different\nsubprojects, and we will be covering SIG Architecture: API\nGovernance.\nIn this SIG Architecture spotlight we talked with Jordan Liggitt, lead\nof the API Gove','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-02-12T00:00:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(247,'https://kubernetes.io/blog/2026/02/03/introducing-node-readiness-controller/','Introducing Node Readiness Controller',replace('\nIn the standard Kubernetes model, a node’s suitability for workloads hinges on a single binary &quot;Ready&quot; condition. However, in modern Kubernetes environments, nodes require complex infrastructure dependencies—such as network agents, storage','\n',char(10)),'https://kubernetes.io/node-readiness-controller-logo.svg','2026-02-03T02:00:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(248,'https://kubernetes.io/blog/2026/01/30/new-cgroup-v1-to-v2-cpu-conversion-formula/','New Conversion from cgroup v1 CPU Shares to v2 CPU Weight',replace('I''m excited to announce the implementation of an improved conversion formula\nfrom cgroup v1 CPU shares to cgroup v2 CPU weight. This enhancement addresses\ncritical issues with CPU priority allocation for Kubernetes workloads when\nrunning on systems w','\n',char(10)),'https://kubernetes.io/blog/2026/01/30/new-cgroup-v1-to-v2-cpu-conversion-formula/linear-conversion.png','2026-01-30T16:00:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(249,'https://kubernetes.io/blog/2026/01/29/ingress-nginx-statement/','Ingress NGINX: Statement from the Kubernetes Steering and Security Response Committees','In March 2026, Kubernetes will retire Ingress NGINX, a piece of critical infrastructure for about half of cloud native environments. The retirement of Ingress NGINX was announced for March 2026, after years of public warnings that the project was in ','https://via.placeholder.com/400x250?text=Tech+News','2026-01-29T00:00:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(250,'https://kubernetes.io/blog/2026/01/28/experimenting-gateway-api-with-kind/','Experimenting with Gateway API using kind',replace('This document will guide you through setting up a local experimental environment with Gateway API on kind. This setup is designed for learning and testing. It helps you understand Gateway API concepts without production complexity.\nCaution:This is an','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-01-28T00:00:00','Kubernetes Blog','Cloud');
INSERT INTO news VALUES(251,'https://kubernetes.io/blog/2026/01/27/cluster-api-v1-12-release/','Cluster API v1.12: Introducing In-place Updates and Chained Upgrades',replace('Cluster API brings declarative management to Kubernetes cluster lifecycle, allowing users and platform teams to define the desired state of clusters and rely on controllers to continuously reconcile toward it.\nSimilar to how you can use StatefulSets ','\n',char(10)),'https://kubernetes.io/blog/2026/01/27/cluster-api-v1-12-release/in-place.svg','2026-01-27T16:00:00','Kubernetes Blog','Cloud');
