INSERT INTO news VALUES(514,'https://blog.railway.com/p/delve-railway-integration','Introducing the Railway integration on Delve.co','Compliance slows down deals. Railway is partnering with Delve to help Railway users automate the busywork and get certified in days instead of months.','https://res.cloudinary.com/railway/image/upload/v1765394874/Introducing_the_Railway_integration_on_Delve.co-1_xksdov.png','2025-12-10T00:00:00','Railway Blog','Dev Tools');
INSERT INTO news VALUES(515,'https://blog.railway.com/p/mindfort-railway','MindFort Runs 100+ AI Pen Testing Agents Without Their Previous $10k AWS Bill','MindFort discovered Railway''s unique pricing model perfectly aligned with their architecture needs. They could maintain massive capacity without paying for idle compute.','https://res.cloudinary.com/railway/image/upload/v1765227326/mindfort-customer-story_gsmmg3.png','2025-12-07T00:00:00','Railway Blog','Dev Tools');
INSERT INTO news VALUES(516,'https://blog.railway.com/p/bilt-deliver-scale','How Bilt''s Marketing Engineering Team Delivers at Scale with Railway','Railway''s developer-first platform enabled the marketing engineering team to focus on what matters most: shipping features that serve millions of customers across the country.','https://res.cloudinary.com/railway/image/upload/v1765227325/bilt-customer-story_wgggxj.png','2025-12-07T00:00:00','Railway Blog','Dev Tools');
INSERT INTO news VALUES(517,'https://blog.railway.com/p/g2x-railway-innovation','How G2X Unlocked Rapid Experimentation at Scale with Railway','How G2X cut infrastructure costs by 87% and deployed 7x faster after migrating their federal contractor platform from a major cloud provider to Railway.','https://res.cloudinary.com/railway/image/upload/v1769088008/g2x-customer-story_p9wtng_fg6l2q.png','2025-12-07T00:00:00','Railway Blog','Dev Tools');
INSERT INTO news VALUES(518,'https://blog.railway.com/p/1M-paid-to-developers-who-built-railway-templates','~$1 Million Paid to Developers Who Built Railway Templates','Railway has paid over $700,000 to template creators—real money, not credits. Here''s how the Template Kickback program works and why we think it''s a better model for compensating open-source contribution.','https://res.cloudinary.com/railway/image/upload/v1764951541/1_Million_Paid_to_Developers_Who_Built_Railway_Templates-_featured_hcufnx.png','2025-12-05T00:00:00','Railway Blog','Dev Tools');
INSERT INTO news VALUES(519,'https://blog.cloudflare.com/making-rust-workers-reliable/','Making Rust Workers reliable: panic and abort recovery in wasm‑bindgen','Panics in Rust Workers were historically fatal, poisoning the entire instance. By collaborating upstream on the wasm‑bindgen project, Rust Workers now support resilient critical error recovery, including panic unwinding using WebAssembly Exception Ha','https://via.placeholder.com/400x250?text=Tech+News','2026-04-22T13:00:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(520,'https://blog.cloudflare.com/past-bots-and-humans/','Moving past bots vs. humans','As AI assistants and privacy proxies challenge the capabilities of traditional bot detection, the Web needs new models for accountability. We believe that control should remain with the client, and that an open ecosystem of anonymous credentials is k','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/61L0GkCvWVQl8TH2i2iwFp/899b2a1936aa7fbfaab45fca71d319d6/1.png','2026-04-21T13:00:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(521,'https://blog.cloudflare.com/agents-week-in-review/','Building the agentic cloud: everything we launched during Agents Week 2026','Agents Week 2026 is a wrap. Let’s take a look at everything we announced, from compute and security to the agent toolbox, platform tools, and the emerging agentic web. Everything we shipped for the agentic cloud.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/6GiG5cEdgwoLU94AuUuLfS/f9022abc8ce823ef2468860474598b6f/BLOG-3239_2.png','2026-04-20T13:00:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(522,'https://blog.cloudflare.com/internal-ai-engineering-stack/','The AI engineering stack we built internally — on the platform we ship','We built our internal AI engineering stack on the same products we ship. That means 20 million requests routed through AI Gateway, 241 billion tokens processed, and inference running on Workers AI, serving more than 3,683 internal users. Here''s how w','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/3lMKwBTT3m7DDmS4BnoNhB/9002104b9c6c09cf72f4052d71e22363/BLOG-3270_2.png','2026-04-20T13:00:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(523,'https://blog.cloudflare.com/ai-code-review/','Orchestrating AI Code Review at scale','Learn about how we built a CI-native AI code reviewer using OpenCode that helps our engineers ship better, safer code.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/7mAft27PsDQnNSNCvF7waU/fdd2c1c448e1863e34f71c124fa85ea1/BLOG-3284_2.jpg','2026-04-20T13:00:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(524,'https://blog.cloudflare.com/agent-readiness/','Introducing the Agent Readiness score. Is your site agent-ready?','The Agent Readiness score can help site owners understand how well their websites support AI agents. Here we explore new standards, share Radar data, and detail how we made Cloudflare’s docs the most agent-friendly on the web.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/sGg5lZjafjQ398V7hYyMv/93e112a34754e2065ffbf6445ebc4500/unnamed.png','2026-04-17T13:05:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(525,'https://blog.cloudflare.com/shared-dictionaries/','Shared Dictionaries: compression that keeps up with the agentic web','Today, we’re excited to give you a sneak peek of our support for shared compression dictionaries, show you how it improves page load times, and reveal when you’ll be able to try the beta yourself.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/2g2NBi1d4eqLAgksGetult/ea05b48519edfa8cccde6d6531700ce1/image5.png','2026-04-17T13:02:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(526,'https://blog.cloudflare.com/ai-redirects/','Redirects for AI Training enforces canonical content','Soft directives don’t stop crawlers from ingesting deprecated content. Redirects for AI Training allows anybody on Cloudflare to redirect verified crawlers to canonical pages with one toggle and no origin changes.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/4zPrHtLf1BbHxQXQHTK1Qs/21a75531129332d749210d67b2c330ad/BLOG-3263_2.png','2026-04-17T13:00:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(527,'https://blog.cloudflare.com/unweight-tensor-compression/','Unweight: how we compressed an LLM 22% without sacrificing quality','Running LLMs across Cloudflare’s network requires us to be smarter and more efficient about GPU memory bandwidth. That’s why we developed Unweight, a lossless inference-time compression system that achieves up to a 22% model footprint reduction, so t','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/4aOVSF1i241gGUwrPrhLfC/21a4f5984b89e56b1ec637f8dbe3c794/1.png','2026-04-17T13:00:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(528,'https://blog.cloudflare.com/introducing-agent-memory/','Agents that remember: introducing Agent Memory','Cloudflare Agent Memory is a managed service that gives AI agents persistent memory, allowing them to recall what matters, forget what doesn''t, and get smarter over time.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/1Cjj8uXbZRCrQVAxirTo7y/d62b5b798990540e78825747ff24afec/image3.png','2026-04-17T13:00:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(529,'https://blog.cloudflare.com/network-performance-agents-week/','Agents Week: network performance update','By migrating our request handling layer to a Rust-based architecture called FL2, Cloudflare has increased its performance lead to 60% of the world’s top networks. We use real-user measurements and connection trimeans to ensure our data reflects the a','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/3i0DbxnemIuOa0tSlgeHul/762f6315b90436796a458d98270eccc5/BLOG-3236_2.png','2026-04-17T13:00:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(530,'https://blog.cloudflare.com/flagship/','Introducing Flagship: feature flags built for the age of AI','We are launching Flagship, a native feature flag service built on Cloudflare’s global network to eliminate the latency of third-party providers. By using KV and Durable Objects, Flagship allows for sub-millisecond flag evaluation.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/1nKDxB6OkUr1fpVKGWEugC/8fc4dbf0bd1ec45e30010a223982487e/image2.png','2026-04-17T13:00:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(531,'https://blog.cloudflare.com/ai-platform/','Cloudflare’s AI Platform: an inference layer designed for agents','We''re building AI Gateway into a unified inference layer for AI, letting developers call models from 14+ providers. New features include Workers AI binding integration and an expanded catalog with multimodal models.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/2ez5tichGEEn5k6SzCgWLm/380a685b14ee9732fdf87c6f88c8f39e/BLOG-3209_2.png','2026-04-16T14:05:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(532,'https://blog.cloudflare.com/high-performance-llms/','Building the foundation for running extra-large language models','We built a custom technology stack to run fast large language models on Cloudflare’s infrastructure. This post explores the engineering trade-offs and technical optimizations required to make high-performance AI inference accessible.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/5j6AEIF1GMhnHuJD08VQtw/9e65e2badc5fd1e75557230e8f455ccc/BLOG-3266_2.png','2026-04-16T14:00:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(533,'https://blog.cloudflare.com/artifacts-git-for-agents-beta/','Artifacts: versioned storage that speaks Git','Give your agents, developers, and automations a home for code and data. We’ve just launched Artifacts: Git-compatible versioned storage built for agents. Create tens of millions of repos, fork from any remote, and hand off a URL to any Git client.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/35SxJbQfntIscpotc0GBt8/48ae11213d7483c9b488321baacf78e7/BLOG-3269_2.png','2026-04-16T13:01:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(534,'https://blog.cloudflare.com/ai-search-agent-primitive/','AI Search: the search primitive for your agents','AI Search is the search primitive for your agents. Create instances dynamically, upload files, and search across instances with hybrid retrieval and relevance boosting. Just create a search instance, upload, and search.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/1b8NdFL2HDBy8FqBHEI679/f17ed98d45fb9b42a616e0b464460489/BLOG-3240_2.png','2026-04-16T13:00:22','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(535,'https://blog.cloudflare.com/deploy-planetscale-postgres-with-workers/','Deploy Postgres and MySQL databases with PlanetScale + Workers','Learn how to deploy PlanetScale Postgres and MySQL databases via Cloudflare and connect Cloudflare Workers.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/5Tj4gJrV5hxlIWxlmoXVZe/7661c1e47c0c868b88301b5f4aca4441/BLOG-3213_2.png','2026-04-16T13:00:22','Cloudflare Blog','Engineering');
