INSERT INTO news VALUES(537,'https://blog.cloudflare.com/project-think/','Project Think: building the next generation of AI agents on Cloudflare','Announcing a preview of the next edition of the Agents SDK — from lightweight primitives to a batteries-included platform for AI agents that think, act, and persist.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/6yokfTVcg8frH4snf7c4sp/2306d721650b4956b28e2198f7cf915d/BLOG-3200_2.png','2026-04-15T13:01:00','Cloudflare Blog','Engineering');
INSERT INTO news VALUES(538,'https://blog.cloudflare.com/introducing-agent-lee/','Introducing Agent Lee - a new interface to the Cloudflare stack','Agent Lee is an in-dashboard agent that shifts Cloudflare’s interface from manual tab-switching to a single prompt. Using sandboxed TypeScript, it helps you troubleshoot and manage your stack as a grounded technical collaborator.','https://cf-assets.www.cloudflare.com/zkvhlag99gkb/2Iva79HIiHPUrK8NLukkwH/dd1cf1709ab04f6d5825124cecd20a5e/BLOG-3231_2.png','2026-04-15T13:00:00','Cloudflare Blog','Engineering');
