INSERT INTO news VALUES(544,'https://discord.com/blog/discord-update-march-24-2026-changelog','Discord Update: March 24, 2026 Changelog','Here''s the Discord Changelog from March 24, 2026, so you can stay informed on what’s new in recent app updates!','https://cdn.prod.website-files.com/5f9072399b2640f14d6a2bf4/65e0d5d41a1beac596a12aaa_March%20Changelog%20Headers.png','2026-03-24T00:00:00','Discord Blog','Engineering');
