INSERT INTO news VALUES(1013,'https://www.swiftbysundell.com/podcast/122','Podcast: “Swift concurrency in practice”, with special guest Ben Scheirman','Ben Scheirman returns to the show to discuss how Swift’s built-in concurrency features, such as async/await and tasks, can be used in practice when building apps for Apple’s platforms.','https://via.placeholder.com/400x250?text=Tech+News','2022-11-18T19:30:00','Swift by Sundell','Mobile');
INSERT INTO news VALUES(1014,'https://www.swiftbysundell.com/articles/opaque-return-types-primary-associated-types','Combining opaque return types with primary associated types','How Swift’s opaque return types can be combined with primary associated types in order to create powerful abstractions without the need for any type erasure.','https://via.placeholder.com/400x250?text=Tech+News','2022-11-12T12:50:00','Swift by Sundell','Mobile');
INSERT INTO news VALUES(1015,'https://www.swiftbysundell.com/podcast/121','Podcast: “Responsive and smooth UIs”, with special guest Adam Bell','Adam Bell returns to the podcast to discuss different techniques and approaches for optimizing UI code, and how to utilize tools like animations in order to build iOS apps that feel fast and responsive.','https://via.placeholder.com/400x250?text=Tech+News','2022-10-31T17:45:00','Swift by Sundell','Mobile');
INSERT INTO news VALUES(1016,'https://www.swiftbysundell.com/podcast/120','Podcast: “Freelancing and WWDC22 highlights”, with special guest Donny Wals','Donny Wals returns to the show to talk about being an iOS developer freelancer, and to discuss some of the key new APIs, Swift language features, and frameworks that were introduced at WWDC22.','https://via.placeholder.com/400x250?text=Tech+News','2022-09-17T15:35:00','Swift by Sundell','Mobile');
INSERT INTO news VALUES(1017,'https://www.swiftbysundell.com/podcast/119','Podcast: “The role of system design”, with special guest Gui Rambo','Gui Rambo returns to the show to talk about the role and importance of system design when building apps and open source tools, and how common app architectures and design patterns can be augmented with custom systems.','https://via.placeholder.com/400x250?text=Tech+News','2022-08-31T17:15:00','Swift by Sundell','Mobile');
INSERT INTO news VALUES(1018,'https://www.swiftbysundell.com/sponsor/essential-developer-july-2022','Sponsored: Essential Developer','Thanks a lot to Essential Developer for sponsoring Swift by Sundell.','https://via.placeholder.com/400x250?text=Tech+News','2022-07-13T10:00:00','Swift by Sundell','Mobile');
INSERT INTO news VALUES(1019,'https://www.swiftbysundell.com/podcast/118','Podcast: “What’s new in SwiftUI in iOS 16?”, with special guest Natalia Panferova','Natalia Panferova joins John to discuss some of the key new features that are coming to SwiftUI and UIKit in iOS 16, and to talk about her experience working on SwiftUI at Apple.','https://via.placeholder.com/400x250?text=Tech+News','2022-07-11T13:30:00','Swift by Sundell','Mobile');
