INSERT INTO news VALUES(1021,'https://www.swiftbysundell.com/podcast/117','Podcast: “Swift 5.7, generics, and the road to Swift 6”, with special guest Ben Cohen','Ben Cohen, manager of the Swift team at Apple, joins John on this WWDC22 special to discuss Swift 5.7, how generics have been made more powerful and easy to use, and how the language is expected to evolve towards Swift 6.','https://via.placeholder.com/400x250?text=Tech+News','2022-06-10T15:10:00','Swift by Sundell','Mobile');
