INSERT INTO news VALUES(1152,'https://blog.ethereum.org/en/2026/03/13/ef-mandate','The Promise of Ethereum: Introducing the EF Mandate','Dearest Friends,  Today we are publishing the EF Mandate, a document that serves as part constitution, part manifesto, and part guide for the Ethereum Foundation.  It is written primarily for the EF itself: to be clear about what we are here to do, t','https://via.placeholder.com/400x250?text=Tech+News','2026-03-13T00:00:00','Ethereum Foundation','Web3');
