INSERT INTO news VALUES(1158,'https://blog.ethereum.org/en/2026/02/17/ethereum-protocol-studies-26','Ethereum Protocol Studies 2026','tl;dr: Ethereum Protocol Studies returns for 2026 with new content tracks in cryptography, lean consensus and zkEVM, plus a new self-paced learning platform. The program kicks off February 23rd. Visit epf.wiki to get started.  Ethereum Protocol Studi','https://via.placeholder.com/400x250?text=Tech+News','2026-02-17T00:00:00','Ethereum Foundation','Web3');
INSERT INTO news VALUES(1159,'https://blog.ethereum.org/en/2026/02/13/leadership-update','Executive Leadership Update','Today, we are announcing a transition in the executive leadership team at the Ethereum Foundation. After extensive contributions to the Foundation’s mission and operations, Tomasz Stańczak has decided to step down from his role as Co-Executive Direct','https://via.placeholder.com/400x250?text=Tech+News','2026-02-13T00:00:00','Ethereum Foundation','Web3');
