INSERT INTO news VALUES(1161,'https://blog.ethereum.org/en/2026/02/05/phd-fellowship','Introducing the EF Academic Secretariat 2026 PhD Fellowship','The EF''s Academic Secretariat team is proud to announce the launch of the inaugural PhD Fellowship Program, a pioneering initiative aimed at empowering and expanding the frontiers of Ethereum-related academic research, by supporting Ethereum-related ','https://via.placeholder.com/400x250?text=Tech+News','2026-02-05T00:00:00','Ethereum Foundation','Web3');
INSERT INTO news VALUES(1162,'https://blog.ethereum.org/en/2026/02/03/1ts-day-devconnect-ba','Trillion Dollar Security Day at Devconnect','During Devconnect Buenos Aires, the Ethereum Foundation and Secureum TrustX brought together Ethereum security practitioners for Trillion Dollar Security Day, a focused event exploring what it would take to securely support a trillion-dollar Ethereum','https://via.placeholder.com/400x250?text=Tech+News','2026-02-03T00:00:00','Ethereum Foundation','Web3');
