INSERT INTO news VALUES(1182,'https://changelog.com/podcast/675','Setting Docker Hardened Images free (Changelog Interviews #675)','In May of 2025, Docker launched Hardened Images, a secure, minimal, production-ready set of images. In December, they made DHI freely available and open source to everyone who builds software. On this episode, we''re joined by Tushar Jain, EVP of Engi','https://via.placeholder.com/400x250?text=Tech+News','2026-02-04T20:00:00','Changelog','Open Source');
INSERT INTO news VALUES(1183,'https://changelog.com/news/179','The tech monoculture is finally breaking (Changelog News #179)','Jason Willems believes the tech monoculture is finally breaking, Don Ho shares some bad Notepad++ news, Tailscale''s Avery Pennarun pens a great downtime apology, Milan Milanović explains why you can only code 4 hours per day, and Addy Osmani on manag','https://via.placeholder.com/400x250?text=Tech+News','2026-02-02T20:30:00','Changelog','Open Source');
