INSERT INTO news VALUES(2746,'https://tympanus.net/codrops/2026/04/27/rhumb-studio-small-but-mighty-shaped-by-curiosity/','Rhumb Studio: Small but Mighty, Shaped by Curiosity','A two-person studio working between Bristol and Paris, redefining web design by crafting immersive, spatial experiences that feel less like pages and more like places.','https://via.placeholder.com/400x250?text=Tech+News','2026-04-27T14:10:56','Codrops','Tech News');
