INSERT INTO news VALUES(2750,'https://tympanus.net/codrops/2026/04/21/false-earth-from-webgl-limits-to-a-webgpu-driven-world/','False Earth: From WebGL Limits to a WebGPU-Driven World','A deep dive into building an infinite procedural landscape using WebGPU and Three.js, where compute shaders and indirect drawing bring millions of interactive grass blades to life.','https://via.placeholder.com/400x250?text=Tech+News','2026-04-21T15:37:48','Codrops','Tech News');
