INSERT INTO news VALUES(2775,'https://news.vuejs.org/issues/174','#174 - Important: Upgrade to Vue-CLI v4.2.0; Enjoy the Vue: Episode #2; Build your own testing framework for Vue 3.0 and more!',replace('Hi there,\n\nI hope you had a great week!\n\nIf you are using the Vue CLI UI, it is __recommended that you upgrade as soon as possible__ to the [new release (v4.2.0) of Vue-CLI](https://github.com/vuejs/vue-cli/releases/tag/v4.2.0). It comes with an impo','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2020-02-10T00:00:00','Vue Official','Frontend');
INSERT INTO news VALUES(2776,'https://news.vuejs.org/issues/173','#173 - 🐉 Welcome Ben "bencodezen" Hong; Enjoy the Vue #1 Episode is here; VuePress v1.3.0 released and more!',replace('Hey,\n\nI’m very happy to let you know that [Ben Hong aka bencodezen](https://twitter.com/bencodezen) has recently joined the Vue.js core team! Rumors say, he’s actually a blue-scaled dragon that escaped Hogwarts during the Triwizard Tournament, but th','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2020-01-31T00:00:00','Vue Official','Frontend');
INSERT INTO news VALUES(2777,'https://news.vuejs.org/issues/172','#172 - Good and bad news from the team; Vue-Watch – the go-to place for finding quality Vue libraries and more!',replace('Hello,\n\nlet’s start with the good news first. The vue-test-utils project has now 4 new maintainers: [Jessica Sachs](https://twitter.com/_JessicaSachs), [Lachlan Miller](https://twitter.com/lachlan19900), [Dobromir Hristov](https://twitter.com/d_m_hri','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2020-01-23T00:00:00','Vue Official','Frontend');
INSERT INTO news VALUES(2778,'https://news.vuejs.org/issues/171','#171 - Try out Vue 3.0-alpha now; GraphQL with Composition-API? Check out Vue-Apollo v4 and Villus and more!',replace('Hello,\n\nI have some pretty great news for you! Have you already tried running Vue 3.0-alpha build? That wasn’t that easy up until recently. But now we have [vue-cli-plugin-vue-next](https://github.com/vuejs/vue-cli-plugin-vue-next)! 🔥\n\nThis makes it ','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2020-01-13T00:00:00','Vue Official','Frontend');
INSERT INTO news VALUES(2779,'https://news.vuejs.org/issues/170','#170 - 🎆 Happy New Year! 🎉 New Nuxt.js version and tons of articles!',replace('Hello,\n\nhave you missed me? As you might have noticed (though I hope you did not and have had some relaxing, off-work holidays instead), I have been on a holiday break from the newsletter. But now I’m back!\n\nAs for the news – there’s a new version of','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2020-01-04T00:00:00','Vue Official','Frontend');
INSERT INTO news VALUES(2780,'https://news.vuejs.org/issues/169','#169 - First talk from VueConfTO published; posva/pinia: the Experimental state-management and more!',replace('Hello Vuers,\n\nany plans for the weekend? Or still standing in line for holiday gifts? If its the latter, here you have something to read on while waiting.\n\nFirst of all, the first talk from VueConf Toronto has been published *[Design Principles of Vu','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2019-12-13T00:00:00','Vue Official','Frontend');
