INSERT INTO news VALUES(2783,'https://news.vuejs.org/issues/166','#166 - eslint-plugin-vue v6.0 released; Speakers announced at VueConfUS and Vue.js Amsterdam;',replace('Hello,\n\nI’m happy to let you know that the speaker lists at the both [VueConf.US](http://vueconf.us/#speakers) and [Vue.js Amsterdam](https://vuejs.amsterdam/#speakers) have been announced! There are some new faces I’m very excited to see talking. Th','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2019-11-21T00:00:00','Vue Official','Frontend');
