INSERT INTO news VALUES(2986,'https://svelte.dev/blog/whats-new-in-svelte-may-2022','What’s new in Svelte: May 2022',replace('With yesterday''s Svelte Summit behind us, we''ve got a lot of news to share! Check out all of the recordings on the Svelte Society YouTube Channel and the rest of this month''s updates below...\nWhat''s new in Svelte\nThe &lt;svelte:element&gt; element le','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2022-05-01T00:00:00','Svelte Official','Frontend');
INSERT INTO news VALUES(2987,'https://svelte.dev/blog/whats-new-in-svelte-april-2022','What’s new in Svelte: April 2022',replace('This month, we felt a shift in the way SvelteKit handles page properties. The last holdout of the use-cases that required fallthrough routes, validating parameter properties, has been replaced by a more specific solution.\nMore on that, and what else ','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2022-04-01T00:00:00','Svelte Official','Frontend');
