INSERT INTO news VALUES(2998,'https://svelte.dev/blog/whats-new-in-svelte-june-2021','What’s new in Svelte: June 2021',replace('This month, we saw lots of contributions to SvelteKit and its docs. The language tools also got some new features, most notably deeper integration with Svelte files within JavaScript or TypeScript files. Let''s jump into the updates...\nNew in SvelteKi','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2021-06-01T00:00:00','Svelte Official','Frontend');
