INSERT INTO news VALUES(3000,'https://svelte.dev/blog/whats-new-in-svelte-april-2021','What’s new in Svelte: April 2021',replace('Two projects that have been months (even years) in the making have made their way out into the world. SvelteKit is now in public beta and slotted components are now available in Svelte!\nWhat''s up with SvelteKit?SvelteKit - Svelte''s versatile framewor','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2021-04-01T00:00:00','Svelte Official','Frontend');
