INSERT INTO news VALUES(3002,'https://svelte.dev/blog/whats-new-in-svelte-march-2021','What’s new in Svelte: March 2021',replace('Lots to cover this month with releases from across the Svelte ecosystem. Most importantly, Svelte Summit Spring 2021 has an Open Call for Speakers. The deadline is March 14 so if you have an idea for a talk, submit it now!\nLet''s dive into the news 🐬\n','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2021-03-01T00:00:00','Svelte Official','Frontend');
