INSERT INTO news VALUES(3018,'https://svelte.dev/blog/the-zen-of-just-writing-css','The zen of Just Writing CSS','It''s fashionable to dislike CSS. There are lots of reasons why that''s the case, but it boils down to this: CSS is unpredictable. If you''ve never had the experience of tweaking a style rule and accidentally breaking some layout that you thought was co','https://via.placeholder.com/400x250?text=Tech+News','2017-09-06T00:00:00','Svelte Official','Frontend');
