INSERT INTO news VALUES(3360,'https://aws.amazon.com/about-aws/whats-new/2026/04/aws-compute-optimizer-ec2-rds/','AWS Compute Optimizer supports 162 new EC2 instance types and 32 new RDS DB instance classes','AWS Compute Optimizer now supports the latest generation of Amazon Elastic Compute Cloud (Amazon EC2) and Amazon Relational Database Service (Amazon RDS) instance types. This expansion enables Compute Optimizer to help you take advantage of the price','https://via.placeholder.com/400x250?text=Tech+News','2026-04-23T18:28:00','Aws Whats New','Cloud & DevOps');
