INSERT INTO news VALUES(3366,'https://aws.amazon.com/about-aws/whats-new/2026/04/redshift-update-delete-merge-iceberg-tables/','Amazon Redshift supports UPDATE, DELETE, MERGE for Apache Iceberg tables','Amazon Redshift now supports row-level UPDATE, DELETE, and MERGE operations on Apache Iceberg tables. Customers who use Iceberg to build interoperable data lakes can now perform data manipulation language (DML) operations directly from Amazon Redshif','https://via.placeholder.com/400x250?text=Tech+News','2026-04-23T15:00:00','Aws Whats New','Cloud & DevOps');
