INSERT INTO news VALUES(3368,'https://aws.amazon.com/about-aws/whats-new/2026/04/s3-five-additional-checksum-algorithms/','Amazon S3 now supports five additional checksum algorithms','Amazon S3 now supports five additional checksum algorithms: MD5, XXHash3, XXHash64, XXHash128, and SHA-512, bringing the total to ten. S3 validates and stores the checksum alongside your object for any of these supported algorithms, so you can verify','https://via.placeholder.com/400x250?text=Tech+News','2026-04-23T13:00:00','Aws Whats New','Cloud & DevOps');
