INSERT INTO news VALUES(3370,'https://aws.amazon.com/about-aws/whats-new/2026/04/sagemaker-unified-studio-vpc/','Amazon SageMaker Unified Studio now supports VPC for notebook kernels','Amazon SageMaker Unified Studio now supports Amazon Virtual Private Cloud (Amazon VPC) for notebook kernels. With this launch, notebook kernels execute within the VPC configured at the domain level, giving enterprises network isolation for interactiv','https://via.placeholder.com/400x250?text=Tech+News','2026-04-23T00:57:00','Aws Whats New','Cloud & DevOps');
