INSERT INTO news VALUES(3445,'https://aws.amazon.com/about-aws/whats-new/2026/04/ec2-c8gn-m8gn-r8gn-ebs/','Amazon EC2 C8gn, M8gn, and R8gn instances now support higher Amazon EBS-optimized performance',replace('Today, AWS announces increased Amazon Elastic Block Store (Amazon EBS) performance for Amazon EC2 C8gn, M8gn, and R8gn instances in 48xlarge and metal-48xl sizes. \nEC2 C8gn, M8gn, and R8gn instances are network optimized instances powered by AWS Grav','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-14T14:01:00','Aws Whats New','Cloud & DevOps');
INSERT INTO news VALUES(3446,'https://azure.microsoft.com/updates?id=502936','Retirement: Prompt Flow in Azure ML and Foundry',replace('Prompt Flow will be retired from Microsoft Foundry and Azure Machine\nLearning on April 20, 2027 and replaced by a single, modern orchestration\nplatform: Microsoft\nAgent Framework. This change unlocks powerful new capabilities,\nincluding a unified, fu','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-27T16:15:55','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3447,'https://azure.microsoft.com/updates?id=560904','[In preview] Public Preview: Azure Backup for Elastic SAN',replace('Azure Backup now supports Elastic SAN, offering a fully\nmanaged solution for backing up and restoring Elastic SAN volumes. This\nintegration helps protect data against accidental deletions, ransomware\nattacks, and application updates by exporting Elas','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-24T18:30:50','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3448,'https://azure.microsoft.com/updates?id=560997','[In preview] Public Preview: Hosted Agents in Foundry Agent Service',replace('Hosted agents run in an isolated execution sandbox\nthat provides a dedicated, secure runtime per agent session. Sessions start\nwith a clean environment with no shared state between sessions, no\ncross-session data leakage, and strong compute boundarie','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-24T18:15:17','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3449,'https://azure.microsoft.com/updates?id=560987','[Launched] Generally Available: Foundry Toolkit for Visual Studio Code (formerly AI Toolkit for VS Code)',replace('Foundry\nToolkit for VS Code is now generally available and provides VS Code tooling for\nMicrosoft Agent Framework, including agent creation from templates or via\nGitHub Copilot, local test/debug with visualization and traces, and direct\ndeployment to','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-24T18:15:17','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3450,'https://azure.microsoft.com/updates?id=560015','[Launched] Generally Available: WireGuard In‑Transit Encryption for Azure Kubernetes Service (AKS)',replace('WireGuard in‑transit encryption is now generally\navailable for Azure Kubernetes Service (AKS) clusters using Azure CNI\npowered by Cilium and Advanced Container Networking Services (ACNS). This capability enables transparent, node‑level encryption\nfor','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-24T18:15:17','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3451,'https://azure.microsoft.com/updates?id=558033','Retirement: Support for .NET 8 (LTS) ends on November 10, 2026—upgrade your apps to .NET 10 (LTS)',replace('On November 10, 2026, support for .NET 8 (LTS)\nwill end. Your apps that are hosted on App Service will continue to run,\nbut security updates will no longer\nbe available and we''ll no longer provide customer service\nfor .NET 8 (LTS). Required action: T','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-24T17:45:05','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3452,'https://azure.microsoft.com/updates?id=560939','[Launched] Generally Available: Cascading read replicas in Azure Database for PostgreSQL',replace('Cascading read replicas are\nnow generally available in Azure Database for PostgreSQL, giving you greater\nflexibility to scale read‑intensive workloads. You can now create\nread replicas from existing ones, creating up to 30 across two\nlevels of replic','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-24T16:45:30','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3453,'https://azure.microsoft.com/updates?id=560889','[Launched] Generally Available: CRC Protection',replace('Azure Elastic SAN now supports CRC-32C checksum verification\nwhen enabled on the client side for connections to Elastic SAN volumes. You can\nenable CRC protection when creating an Elastic SAN or enable it on an existing\nElastic SAN. Elastic SAN also ','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-24T16:45:30','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3454,'https://azure.microsoft.com/updates?id=560919','[Launched] Generally Available: Capacity Autoscaling',replace('Capacity\nAutoscaling support is now generally available on Elastic SAN. Customers can\navoid the constraints of overprovisioning and manual capacity management by\nsetting a policy to automatically expand SAN Capacity based on usage. Autoscaling\nprovid','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-23T18:30:11','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3455,'https://azure.microsoft.com/updates?id=560358','[Launched] Generally Available: Azure Monitor for Azure Arc-enabled Kubernetes with OpenShift and Azure Red Hat OpenShift','Azure Monitor provides a complete set of services for monitoring the health and performance of different layers of your Kubernetes infrastructure and the applications that depend on it.Azure Monitor support for Azure Arc-enabled Kubernetes with OpenS','https://via.placeholder.com/400x250?text=Tech+News','2026-04-23T16:45:55','Azure Updates','Cloud & DevOps');
