INSERT INTO news VALUES(3457,'https://azure.microsoft.com/updates?id=560288','[Launched] Generally Available: Azure Database for PostgreSQL flexible server in Denmark East',replace('You can now\ndeploy Azure Database for PostgreSQL flexible server in the Denmark\nEast Azure region. Learn\nmore.','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-22T17:45:10','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3458,'https://azure.microsoft.com/updates?id=559633','[Launched] Generally Available: Dynamic data masking with Azure Cosmos DB',replace('Dynamic data masking (DDM) is a\nserver-side, policy-based security feature in Azure Cosmos DB that\nhelps your organization protect sensitive data from unauthorized\naccess. DDM dynamically masks data for nonprivileged users, ensuring that\nsensitive in','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-22T17:45:10','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3459,'https://azure.microsoft.com/updates?id=513249','[In preview] Public Preview: Logical replication slot sync Status metric for Azure PostgreSQL Flexible Server',replace('You can now monitor the synchronization status of\nyour logical replication slots in Azure Database for PostgreSQL – Flexible\nServer using the new logical_replication_slot_sync_status metric, now in\npublic preview. This Azure Monitor metric shows whet','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-22T17:45:10','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3460,'https://azure.microsoft.com/updates?id=560336','[Launched] Generally Available: Premium SSD v2 for Azure Database for PostgreSQL','We are excited to announce the general availability of Premium SSD v2 for Azure Database for PostgreSQL flexible server. With Premium SSD v2, you can achieve up to four times higher IOPS, significantly lower latency, and better price-performance for ','https://via.placeholder.com/400x250?text=Tech+News','2026-04-22T17:30:14','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3461,'https://azure.microsoft.com/updates?id=560298','[In preview] Public Preview: Migrating from virtual network-integrated to Private Endpoint–capable network configuration','You can now migrate your Azure Database for PostgreSQL server from a virtual network‑integrated deployment to a network configuration that supports Private Endpoint connectivity. If you originally deployed your server inside a virtual network but now','https://via.placeholder.com/400x250?text=Tech+News','2026-04-22T17:30:14','Azure Updates','Cloud & DevOps');
