INSERT INTO news VALUES(3463,'https://azure.microsoft.com/updates?id=559886','[Launched] Generally Available: Azure Monitor pipeline','Azure Monitor pipeline is now generally available.Azure Monitor pipeline provides a centralized control point for telemetry ingestion and transformation, designed specifically for secure, high‑throughput, enterprise‑scale scenarios. It''s built on ope','https://via.placeholder.com/400x250?text=Tech+News','2026-04-21T20:30:49','Azure Updates','Cloud & DevOps');
