INSERT INTO news VALUES(3468,'https://azure.microsoft.com/updates?id=559311','Retirement: Azure Functions runtime v3 on Linux Consumption will stop running September 30, 2026',replace('Azure Functions runtime v3 was retired on December\n13, 2022. As part of ongoing efforts to reduce reliance on legacy\ninfrastructure and focus investments on supported platforms, Azure will enforce\nthis retirement for Linux Consumption–based Function ','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-17T19:00:12','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3469,'https://azure.microsoft.com/updates?id=560521','[Launched] Generally Available: Configure AKS backup using a single Azure CLI command',replace('Azure Backup\nnow provides a simplified experience to configure backup for Azure\nKubernetes Service (AKS) clusters using a single Azure CLI command.Enabling\nbackup for AKS clusters through CLI requires multiple manual steps, including\ninstallation of ','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-17T17:15:04','Azure Updates','Cloud & DevOps');
