INSERT INTO news VALUES(3471,'https://azure.microsoft.com/updates?id=558483','[In preview] Generally Available: User and group quota reports in Azure NetApp Files',replace('For organizations leveraging individual user and group\nquotas in Azure NetApp Files to manage capacity on NFS, SMB, and dual-protocol\nvolumes, the user and group quota reporting feature offers clear\nvisibility into key metrics such as quota limits, u','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-16T18:00:13','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3472,'https://azure.microsoft.com/updates?id=559751','Retirement: End of life reminder of HBv2/HC-Series/NP-Series Azure Virtual Machine in Azure Batch Pool',replace('Microsoft Azure will retire support for HBv2-series,\nHC-series, and NP-series VMs in Azure Batch pools on May 31, 2027,\nincluding:   \n HBv2-series: 120 AMD EPYC 7V12 vCPUs, 480 GB RAM, 200\n     Gb/s HDR InfiniBand  \n HC-series: 44 Intel Xeon Platinum','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-15T17:30:33','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3473,'https://azure.microsoft.com/updates?id=559761','[Launched] Generally Available: Encrypt Premium SSD v2 and Ultra Disks with Cross Tenant Customer Managed Keys',replace('Cross-tenant customer-managed\nkeys (CMK) for Premium SSD v2 and Ultra Disks are\nnow generally available. This capability allows managed disks to be\nencrypted using a customer-managed key stored in an Azure Key Vault\nlocated in a different Microsoft E','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-15T17:15:38','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3474,'https://azure.microsoft.com/updates?id=560241','[In preview] Public Preview: Azure Site Recovery support for Windows Azure VMs with NVMe disk controllers.','Azure Site Recovery now supports replication and disaster recovery for Windows Azure Virtual Machines running on NVMe-enabled Generation 2 VM families, such as the Da/Ea/Fa v6-series and Ebsv5/Ebdsv5 in the Azure-to-Azure scenario. This enhancement a','https://via.placeholder.com/400x250?text=Tech+News','2026-04-14T21:15:15','Azure Updates','Cloud & DevOps');
