INSERT INTO news VALUES(3480,'https://azure.microsoft.com/updates?id=560119','[In preview] Public Preview: Monitor AKS applications with OpenTelemetry and Azure Monitor','Azure Monitor now supports monitoring applications that run on Azure Kubernetes Service (AKS) by using OpenTelemetry for instrumentation and data collection.Leverage autoinstrumentation to deploy the Azure Monitor OpenTelemetry distro to workloads or','https://via.placeholder.com/400x250?text=Tech+News','2026-04-13T17:45:02','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3481,'https://azure.microsoft.com/updates?id=560001','[Launched] Generally Available: Granular Encryption-in-Transit Controls for SMB and NFS on Azure Files','Azure Files now supports independent configuration of encryption-in-transit settings for SMB and NFS protocols at the storage account level. Customers can now define protocol-specific security policies, enabling precise control over encryption requir','https://via.placeholder.com/400x250?text=Tech+News','2026-04-13T17:45:02','Azure Updates','Cloud & DevOps');
