INSERT INTO news VALUES(3489,'https://azure.microsoft.com/updates?id=559547','[Launched] Generally Available: Azure Red Hat OpenShift adds NVIDIA H100 and H200 GPU support',replace('Azure Red Hat OpenShift (ARO) now supports NVIDIA H100 and\nH200 GPU-based Azure Virtual Machine SKUs, enabling customers to run\nlarge-scale AI, machine learning, and high-performance computing (HPC)\nworkloads on a fully managed OpenShift service. Thi','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-07T19:30:53','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3490,'https://azure.microsoft.com/updates?id=557857','[Launched] Generally Available: Disable HTTP proxy in AKS',replace('Organizations\nthat use HTTP proxies to control outbound traffic often need to change or\nremove those settings as network requirements evolve, which can be disruptive\nin running clusters. Azure Kubernetes Service allows administrators to disable\nHTTP ','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-07T17:45:41','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3491,'https://azure.microsoft.com/updates?id=559981','[Launched] Generally Available: Azure Functions now supports MCP resource triggers',replace('Developers\nbuilding MCP servers on Azure Functions can expose tools but not resources.\nNow, Azure Functions supports MCP resource triggers, enabling\ndevelopers to expose resources directly from an Azure Functions–hosted Model\nContext Protocol (MCP) s','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-07T17:15:12','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3492,'https://azure.microsoft.com/updates?id=557907','[Launched] Generally Available: Pod CIDR expansion in AKS',replace('When clusters\nexhaust available pod IP addresses, teams have historically been forced to\nrebuild environments to restore capacity, creating operational disruption. Pod\nCIDR expansion allows overlay‑based AKS clusters to increase their pod IP range\nin','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-07T17:00:23','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3493,'https://azure.microsoft.com/updates?id=559899','[Launched] Generally Available: Network Security Perimeter for Azure Service Bus','Network Security Perimeter (NSP) support for Azure Service Bus is now generally available. Network Security Perimeter creates a logical network boundary around your Service Bus namespaces and other Azure PaaS resources, blocking unauthorized public a','https://via.placeholder.com/400x250?text=Tech+News','2026-04-06T18:00:04','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3494,'https://azure.microsoft.com/updates?id=559876','[In preview] Public Preview: Rule impact analysis on Azure Network Watcher','Rule impact analysis on Azure Network Watcher enables you to preview the impact of security admin rules and network security group (NSG) rules before applying them to your environment. This feature helps you validate rule behavior, identify potential','https://via.placeholder.com/400x250?text=Tech+News','2026-04-06T16:15:40','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3495,'https://azure.microsoft.com/updates?id=558027','Retirement: Python support for Azure App Service and Azure Functions on Windows will be retired on March 31, 2027',replace('Starting March 31, 2027,\nPython applications hosted on Azure App Service on\nWindows and Azure Functions on Windows will no longer run. After\nthis date:  \n Your application configuration and content will\n     remain intact  \n Your apps will stop runni','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-02T16:45:52','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3496,'https://azure.microsoft.com/updates?id=558276','Retirement: AzureDnsEndpoints for Azure storage accounts will be retired March 2027',replace('AzureDnsZone\nendpoints (preview) for Azure Blob storage accounts will enter\nretirement in March 2027. Customers leveraging AzureDnsZone endpoints (preview)\nshould transition to Standard endpoints for all new and existing blob storage\naccount deployme','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-04-02T16:30:09','Azure Updates','Cloud & DevOps');
