INSERT INTO news VALUES(3509,'https://azure.microsoft.com/updates?id=559406','[Launched] Generally Available: Microsoft Azure now available from new cloud region in Denmark',replace('Microsoft announces the opening of its cloud region in\nDenmark to accelerate digital transformation and AI innovation. The Denmark\nEast region provides Danish customers with local, secure cloud infrastructure,\nsupporting local data residency, low lat','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-03-31T17:15:56','Azure Updates','Cloud & DevOps');
