INSERT INTO news VALUES(3517,'https://azure.microsoft.com/updates?id=558879','[Launched] Generally Available: Azure SQL updates for late-March 2026',replace('In late-March 2026, the following updates and\nenhancements were made to Azure SQL:  \n Configure built-in SQL code analysis rules and\n     severity settings without editing project XML.  \n Use Fabric connectivity\n     and provisioning options to conne','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-03-26T16:00:10','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3518,'https://azure.microsoft.com/updates?id=558836','[Launched] Generally Available: Cosmos DB Mirroring in Microsoft Fabric with private endpoints','We''re excited to announce that private endpoint support for Azure Cosmos DB Mirroring in Microsoft Fabric is now generally available. You can now unlock powerful analytics on your operational data while keeping your enhanced network security posture ','https://via.placeholder.com/400x250?text=Tech+News','2026-03-25T20:00:39','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3519,'https://azure.microsoft.com/updates?id=557862','[In preview] Public Preview: Blue-green agent pool upgrade in AKS',replace('In‑place node pool upgrades can introduce risk by applying changes\ndirectly to running environments. Blue‑green agent pool upgrades create a\nparallel node pool with the new configuration, allowing validation before\nworkloads are shifted and providing','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-03-25T20:00:39','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3520,'https://azure.microsoft.com/updates?id=558841','[In preview] Public Preview: Fabric Mirroring integration for Azure Database for MySQL','We are excited to announce the public preview of Fabric Mirroring integration for Azure Database for MySQL – Flexible Server. You can now replicate MySQL operational data into Microsoft Fabric in near real time, without building or maintaining ETL pi','https://via.placeholder.com/400x250?text=Tech+News','2026-03-25T17:45:33','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3521,'https://azure.microsoft.com/updates?id=558884','[Launched] Public Preview: Azure SQL Managed Instance change event streaming','You can now stream row‑level data changes—inserts, updates, and deletes—from Azure SQL Managed Instance to Azure Event Hubs in near real time with change event streaming (CES). SQL publishes changes as transactions commit, reducing latency while mini','https://via.placeholder.com/400x250?text=Tech+News','2026-03-25T17:30:45','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3522,'https://azure.microsoft.com/updates?id=558870','[Launched] Generally Available: Custom time zone support for pg_cron via cron.timezone in Azure Database for PostgreSQL','You can now modify the cron.timezone server parameter in Azure Database for PostgreSQL. This parameter controls the time zone used by pg_cron when evaluating scheduled jobs. By configuring cron.timezone, you can ensure scheduled jobs run according to','https://via.placeholder.com/400x250?text=Tech+News','2026-03-25T17:30:45','Azure Updates','Cloud & DevOps');
