INSERT INTO news VALUES(3526,'https://azure.microsoft.com/updates?id=557902','[Launched] Generally Available: Container network metrics filtering for AKS',replace('Network\nobservability can generate large volumes of metrics, making it difficult for\nteams to focus on data that is operationally relevant. Container network\nmetrics filtering in Azure Container Networking Services (ACNS) allows\noperators to control ','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-03-24T23:00:18','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3527,'https://azure.microsoft.com/updates?id=557887','[In preview] Public Preview: AI Agent for container networking troubleshooting',replace('Troubleshooting Kubernetes networking issues is often slowed by logs and\nmetrics scattered across multiple tools, forcing engineers to manually\ncorrelate signals during incidents. The container networking agent provides a\nlightweight, web‑based inter','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-03-24T21:45:26','Azure Updates','Cloud & DevOps');
