INSERT INTO news VALUES(3537,'https://azure.microsoft.com/updates?id=558086','Retirement: Azure SQL Elastic query - Shard_Map_Manager mode','Starting March 31, 2027 Elastic query using Shard_Map_Manager external data source type reaches end of support.Existing workloads can continue to run using Azure SQL Elastic query - Shard_Map_Manager mode, but will no longer receive updates or suppor','https://via.placeholder.com/400x250?text=Tech+News','2026-03-20T19:00:50','Azure Updates','Cloud & DevOps');
