INSERT INTO news VALUES(3555,'https://azure.microsoft.com/updates?id=557094','Retirement: Azure VMware Solution AV36P and AV52 node retirement on June 30, 2029','Microsoft is announcing the retirement of the AV36P and AV52 Nodes on June 30, 2029. The terms of your current AV36P and AV52 Reserved Instance (RI) are not affected by this announcement. At this time, we recommend that you review your current RI exp','https://via.placeholder.com/400x250?text=Tech+News','2026-03-17T17:30:11','Azure Updates','Cloud & DevOps');
INSERT INTO news VALUES(3556,'https://azure.microsoft.com/updates?id=549077','Retirement: Support for Windows Server 2016 Marketplace images on Azure Batch pools will end on January 12, 2027','Azure Batch periodically retires support for operating systems that reach end-of-life status. Support for Windows Server 2016 concluded on January 11, 2022, with extended support scheduled to end on January 12, 2027. Marketplace images for Windows Se','https://via.placeholder.com/400x250?text=Tech+News','2026-03-16T18:45:11','Azure Updates','Cloud & DevOps');
