INSERT INTO news VALUES(3559,'https://azure.microsoft.com/updates?id=516070','Retirement: End of life reminder of NVv3 and NVv4-series Azure virtual machine in Azure Batch pools','Microsoft Azure will retire support for NVv3 or NVv4-series VMs on September 30th, 2026, including NVv3 Series (NVIDIA Tesla M60 GPU): Standard_NV12s_v3, Standard_NV12hs_v3, Standard_NV24s_v3, Standard_NV24ms_v3, Standard_NV32ms_v3, Standard_NV48s_v3','https://via.placeholder.com/400x250?text=Tech+News','2026-03-16T18:30:34','Azure Updates','Cloud & DevOps');
