INSERT INTO news VALUES(3561,'https://azure.microsoft.com/updates?id=558656','[Launched] Generally Available: Summary rules in Log Analytics workspace now support manual “Retry bin”',replace('Summary rules run batch aggregation inside your Log\nAnalytics workspace and re-ingest the summarized results into a custom\ndestination table. When a bin fails, that can create gaps in your summarized\ndataset. “Retry bin” helps you remediate bin-level','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-03-12T21:15:25','Azure Updates','Cloud & DevOps');
