INSERT INTO news VALUES(3563,'https://azure.microsoft.com/updates?id=558145','[Launched] Generally Available: Terraform, Bicep, Ansible support for elastic clusters on Azure Database for PostgreSQL',replace('You can now provision and manage Azure Database for\nPostgreSQL elastic clusters using Terraform, Bicep, and Ansible, with\nfull General Availability support. With\nnative infrastructure-as-code support, you can consistently create,\nscale, and manage el','\n',char(10)),'https://via.placeholder.com/400x250?text=Tech+News','2026-03-11T18:00:35','Azure Updates','Cloud & DevOps');
