INSERT INTO news VALUES(3646,'https://nyheter.aitool.se/ai-musik-splittrar-sverige-hitlat-portas-fran-topplistan/','AI-musik splittrar Sverige: hitlåt portas från topplistan','När en hitlåt inte får vara hit – AI-musiken som splittrar Sverige Sveriges mest spelade låt på Spotify får inte räknas. &#8221;Jag vet, du är inte min&#8221; av artisten Jacub har strömmat över fem miljoner gånger och legat etta på Spotifys topplist','https://via.placeholder.com/400x250?text=Tech+News','2026-01-22T08:32:00','Ai Tool News','AI');
INSERT INTO news VALUES(3647,'https://nyheter.aitool.se/nvidia-blasvader-efter-kontakt-med-piratbiblioteket-annas-archive/','Nvidia blåsväder efter kontakt med piratbiblioteket Anna’s Archive','Nvidia anklagats för att medvetet ha använt miljontals piratkopierade böcker för att träna sina AI-modeller efter att företaget kontaktade det kontroversiella &#8221;skuggbiblioteket&#8221; Anna&#8217;s Archive. Uppgifterna framkommer i en uppdaterad','https://via.placeholder.com/400x250?text=Tech+News','2026-01-22T06:24:00','Ai Tool News','AI');
