INSERT INTO news VALUES(3649,'https://nyheter.aitool.se/ai-foretagen-ljuger-llm-modeller-har-lagrat-hela-upphovsrattsskyddade-bocker/','AI-företagen ljuger: LLM-modeller har lagrat hela upphovsrättsskyddade böcker','AI-företag som OpenAI, Anthropic och Google har konsekvent hävdat att deras språkmodeller inte lagrar kopior av träningsdata, utan bara &#8221;lär sig mönster&#8221;. I inlagor till den amerikanska Copyright Office har flera företag aktivt förnekat a','https://via.placeholder.com/400x250?text=Tech+News','2026-01-20T10:55:00','Ai Tool News','AI');
INSERT INTO news VALUES(3650,'https://nyheter.aitool.se/lakare-varnar-for-nya-chatgpt-health-funktionen/','Läkare varnar för nya ChatGPT Health funktionen','ChatGPT Health är en ny specialiserad funktion inom ChatGPT som OpenAI lanserade i januari 2026 för att hjälpa användare att bättre förstå och hantera sin egen hälsa. Tjänsten gör det möjligt att säkert koppla samman medicinska journaler och hälsoapp','https://via.placeholder.com/400x250?text=Tech+News','2026-01-20T08:25:00','Ai Tool News','AI');
INSERT INTO news VALUES(3651,'https://nyheter.aitool.se/raspberry-pi-5-har-fatt-en-uppgradering-med-nya-ai-hat-2/','Raspberry Pi 5 får en uppgradering med nya AI HAT+ 2','Raspberry Pi Foundation har precis släppt AI HAT+ 2, ett imponerande tillbehör som förvandlar din Pi 5 till en generativ AI-maskin för bara 130 dollar. Det är en ganska rejäl uppgradering från den ursprungliga AI HAT-kortet. Med AI HAT+ 2 kan du köra','https://via.placeholder.com/400x250?text=Tech+News','2026-01-20T06:30:00','Ai Tool News','AI');
