INSERT INTO news VALUES(3768,'https://www.architecture-weekly.com/p/parse-dont-guess','Parse, Don''t Guess','Last time, I shared with you how sneaky I was on transaction handling.. Today, the opposite: I&#8217;ll tell you how I fixed the issue when I tried to be too sneaky. I already told you that Sneaky Code Bites Back. The moral? Do as I tell, not how I d','https://substackcdn.com/image/fetch/$s_!Rc3Y!,w_1456,c_limit,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F9abd1e13-5804-495b-bbe8-a3cca0867aca_800x420.png','2026-03-02T17:18:15','Architecture Weekly','System Design');
