INSERT INTO news VALUES(5947,'https://onepercentdesign.medium.com/what-is-a-design-system-and-why-should-you-care-9013a3bb7781','What Is a Design System (and Why Should You Care)? | by Widianto | Apr, 2026 | Medium','Have you ever built a button, handed it off to a developer, and then… it comes back looking a bit different?','images/72ff1f5e956fde585c264193c9079cdf.webp','2026-04-27T10:16:56','Medium System Design','System Design');
INSERT INTO news VALUES(5948,'https://medium.com/@saranshbaid102005/designing-a-scalable-llm-benchmarking-system-for-real-world-inference-c5644e7f50e3','Designing a Scalable LLM Benchmarking System for Real-World Inference | by saransh baid | Apr, 2026 | Medium','A systems approach to real-world LLM deployment benchmarking','images/a7e3d90602f986ccae7056f7402ec269.webp','2026-04-27T10:15:27','Medium System Design','System Design');
INSERT INTO news VALUES(5949,'https://www.infoq.com/news/2026/04/qconsf-2026-tracks-announced/','QCon San Francisco 2026: 12 Tracks Announced - InfoQ','The 12 tracks for QCon San Francisco 2026 (November 16-20) are now live. Four tracks cover AI in production. The other eight cover the rest of what senior engineering still demands: distributed systems, architecture teardowns, resilience, platform internals, API design, and Staff+ leadership. Early bird pricing runs until May 12th.','images/edb26b2d3aca02007e3e09d2ddb3c27b.webp','2026-04-27T15:30:00','Infoq','Tech News');
INSERT INTO news VALUES(5950,'https://www.infoq.com/news/2026/04/uber-junit4-junit5-migration/','Uber Migrates 75,000+ Test Classes from Junit 4 to Junit 5 Using Automated Code Transformation - InfoQ','Uber engineers migrated over 75,000 test classes from JUnit 4 to JUnit 5 using automated code transformation with OpenRewrite and internal orchestration. By enabling the JUnit Platform for dual execution with Bazel and validating changes through CI, the team modernized testing infrastructure while maintaining correctness at monorepo scale.','images/4adb056a2d517369c26b55eee1aade87.webp','2026-04-27T14:07:00','Infoq','Tech News');
INSERT INTO news VALUES(5951,'https://www.infoq.com/presentations/OpenTelemetry-instrumentation/','Building a Future-Proof Observability Platform to Empower Engineers - InfoQ','Wayne Bell and Dan Gomez Blanco discuss the architectural and cultural shift required to scale observability at Skyscanner. They share how moving to OpenTelemetry decoupled instrumentation from vendors, and explain why treating a platform as a product - with engineers as customers - is the key to reducing incident rates and eliminating technical debt across 800+ microservices.','images/906c0c88423a2f765c72cb8fe3946ee6.webp','2026-04-27T13:14:00','Infoq','Tech News');
INSERT INTO news VALUES(5952,'https://www.infoq.com/articles/mcp-java-architectural-strategy-llm-integrations/','MCP in the Java World: Bringing Architectural Strategy to LLM Integrations - InfoQ','Discover how the Model Context Protocol (MCP) Java SDK is establishing a new architectural discipline for enterprise LLM integrations. By defining explicit contracts and leveraging MCP servers as anti-corruption layers, it ensures governance, loose coupling, and security alignment with the JVM ecosystem and existing operational practices, moving integrations beyond fragility to resilience.','images/a2b4f7ea4194c0a3ebb9a931e1ef9dbd.webp','2026-04-27T11:00:00','Infoq','Tech News');
INSERT INTO news VALUES(5953,'https://www.infoq.com/podcasts/java-performance-quest/','A Java Performance Quest: Taming Unsafe Code, Embracing Idiomatic Style & Debugging the Linux Kernel - InfoQ','In this podcast, Jaromir Hamala, a seasoned Java engineer specialising in high-throughput data systems, shares his thoughts on how developers can tackle high-performance software development. He touches on the benefits of modern Java that allow writing idiomatic Java code while remaining "mechanically sympathetic", and also on his experience debugging a Linux kernel bug.','images/e44f3f40a45e752395dade59a3a553d6.webp','2026-04-27T11:00:00','Infoq','Tech News');
INSERT INTO news VALUES(5954,'https://www.infoq.com/news/2026/04/junior-developer-pipeline-crisis/','Microsoft''s Russinovich and Hanselman Warn AI Is Hollowing Out the Junior Developer Pipeline - InfoQ','Microsoft''s Russinovich and Hanselman argue in a CACM paper that agentic AI creates an "AI drag" on junior developers while boosting seniors, incentivizing companies to stop hiring entry-level engineers. Entry-level hiring is down 67% since 2022. They propose a preceptor model borrowed from medical education to preserve the talent pipeline.','images/c94fd106a9f2e00f6b5e92bab0995824.webp','2026-04-27T09:17:00','Infoq','Tech News');
INSERT INTO news VALUES(5955,'https://www.infoq.com/news/2026/04/gitlab-flatrate-view-ai-access/','GitLab Adds Flat-Rate Code Reviews, Free-Tier AI Access, and Spending Caps - InfoQ','Open-core DevOps vendor GitLab has shipped versions 18.10 and 18.11 of its DevSecOps platform, with changes that give agentic AI to users on the free tier, that cut the per-review cost of automated code analysis, and give administrators hard limits on how much teams can spend on AI credits each month.','images/13eb3bcd9d4dc02834659d3bf02ab279.webp','2026-04-27T08:00:00','Infoq','Tech News');
INSERT INTO news VALUES(5956,'https://www.infoq.com/news/2026/04/spring-news-roundup-apr20-2026/','Spring News Roundup: First Release Candidates of Boot, Security, Integration, Modulith, AMQP - InfoQ','There was a flurry of activity in the Spring ecosystem during the week of April 20th, 2026, highlighting the first release candidates of: Spring Boot, Spring Security, Spring Integration, Spring Modulith, Spring AMQP, Spring for Apache Kafka and Spring Vault.','images/413cb6eb0874c211013fd6ab154aa9bf.webp','2026-04-27T02:30:00','Infoq','Tech News');
INSERT INTO news VALUES(5957,'https://www.infoq.com/news/2026/04/aws-deprecates-workmail-apprunne/','AWS Ends WorkMail and Moves App Runner to Maintenance Mode - InfoQ','AWS has recently announced that WorkMail will be discontinued and that App Runner will stop accepting new customers and move into maintenance mode. Several other less popular services and features are also entering maintenance or sunset phases, triggering concern and debate across the AWS community.','images/c19776bc583fc6da488f6c0860da61e6.webp','2026-04-26T06:53:00','Infoq','Tech News');
INSERT INTO news VALUES(5958,'https://www.infoq.com/news/2026/04/cache-parallelism-cloudflare/','Cloudflare Optimizes Edge Stack for High-Core CPUs instead of Large Cache - InfoQ','Cloudflare recently introduced its Gen 13 servers, marking a shift in how its network handles traffic. Instead of relying on large CPU caches for speed, the company redesigned its software to leverage many more processor cores working in parallel in its latest AMD-based servers.','images/bab2c4f79ff18ebfb4f6ef17133a5f90.webp','2026-04-25T06:06:00','Infoq','Tech News');
INSERT INTO news VALUES(5959,'https://www.infoq.com/news/2026/04/yelp-cassandra-upgrade/','Yelp Achieves Zero-Downtime Upgrade of over 1,000 Cassandra Nodes - InfoQ','Yelp has completed a large-scale upgrade of its Apache Cassandra infrastructure, spanning more than 1,000 nodes, without any service downtime, offering a blueprint for managing stateful systems at scale.','images/80fcd9394e67246b1eb0e3ee47548e75.webp','2026-04-24T12:00:00','Infoq','Tech News');
INSERT INTO news VALUES(5960,'https://www.infoq.com/presentations/deepfakes-ai/','Deepfakes, Disinformation, and AI Content are Taking over the Internet - InfoQ','Shuman Ghosemajumder explains how generative AI has transformed from a creative curiosity into a high-scale tool for disinformation and fraud. He shares insights on "Disinformation Automation," the fallacy of CAPTCHA in an AI world, and why engineering leaders must adopt zero-trust "cyber fusion" strategies to defend against automated attacks that mimic human behavior with chilling accuracy.','images/0251622df2af2b4713c845c570ae7e71.webp','2026-04-24T09:55:00','Infoq','Tech News');
INSERT INTO news VALUES(5961,'https://www.infoq.com/articles/orchestrating-agentic-multimodal-ai-pipelines-apache-camel/','Orchestrating Agentic and Multimodal AI Pipelines with Apache Camel - InfoQ','In this article, author Vignesh Durai discusses how agentic and multimodal AI systems can be engineered using Apache Camel and LangChain4j technologies. The key components in the solution include LLM-based reasoning, retrieval-augmented generation (RAG), and image classification.','images/008a0883661f8fb26b62a90da7be0072.webp','2026-04-24T09:00:00','Infoq','Tech News');
INSERT INTO news VALUES(5962,'https://www.infoq.com/news/2026/04/vault-2-0-ibm-identity/','HashiCorp Vault 2.0 Marks Shift to IBM Lifecycle with New Identity Federation - InfoQ','HashiCorp has released Vault 2.0, moving to the IBM versioning and support model following its acquisition. The update introduces Workload Identity Federation for secret syncing without static credentials, SCIM 2.0 provisioning, and performance gains in the storage engine. It also prioritises identity-based security and certificate automation while removing legacy architectural components.','images/47258bc4d398a5c007851906cb344bfb.webp','2026-04-24T07:00:00','Infoq','Tech News');
INSERT INTO news VALUES(5963,'https://www.infoq.com/news/2026/04/react-navigation-8-alpha/','React Navigation 8.0 Alpha with Native Bottom Tabs, Reworked TypeScript Inference and History - InfoQ','React Navigation has released version 8.0 in alpha, updating its routing library for React Native and web applications. Notable changes include native bottom tabs as the default, enhanced TypeScript inference, and deep linking enabled by default. The update prioritizes stability and includes a guide for migration from version 7.x.','images/cabfc1140124e4ea8ad9470e67bd622a.webp','2026-04-23T15:36:00','Infoq','Tech News');
INSERT INTO sqlite_sequence VALUES('news',5963);
